@vex.verify(
    assertions=[
        vex.assert_in(['charge_card', 'send_email', 'cancel_order'], 'next_step'),
        vex.assert_not_empty('rollback_path'),
        lambda ctx: ctx.get('approval_needed', False) or ctx.get('amount', 0) < 10000
    ],
    risk_profile='medium',
    tags=['workflow', 'routing']
)
def safe_route(previous_result: str, api_response: str) -> dict:
    router = dspy.ChainOfThought(WorkflowRouter())
    result = router(previous_result=previous_result, api_response=api_response)
    return {
        'next_step': result.next_step,
        'approval_needed': result.approval_needed,
        'rollback_path': f'rollback-{previous_result}'
    }
